const input = $input.first().json;
const component = input.component || input.payload?.component || 'unknown';
const symptom = input.symptom || input.payload?.symptom || input.message || 'unknown';
const severity = input.severity || input.payload?.severity || 'WARN';

return {
  component: component,
  symptom: symptom,
  severity: severity,
  task_id: input.task_id || 'sh-' + Date.now(),
  context: input.context || {}
};

const result = $input.first().json;
const alert = result.alert || {};
const diag = result.diagnosis || {};
const heal = result.result || {};

const icon = heal.success ? '✅' : (heal.action_taken === 'escalated_to_human' ? '👤' : '❌');

return {
  task_id: alert.task_id,
  component: alert.component,
  symptom: alert.symptom,
  root_cause: diag.root_cause,
  safe_to_auto_fix: diag.safe_to_auto_fix,
  action_taken: heal.action_taken,
  success: heal.success,
  duration_ms: heal.duration_ms,
  learned: heal.learned || false,
  summary: `${icon} [${alert.component}] ${diag.root_cause} → ${heal.action_taken} (${heal.success ? '已恢复' : heal.action_taken === 'escalated_to_human' ? '需人工' : '失败'})`,
  timestamp: new Date().toISOString()
};

const data = $input.first().json;

// 需要人工介入时 → 触发 OpenClaw 通知
if (!data.success && data.action_taken === 'escalated_to_human') {
  return {
    notify: true,
    channel: 'feishu',
    level: 'WARN',
    title: `⚠️ ${data.component} 需要人工介入`,
    message: `组件: ${data.component}\n症状: ${data.symptom}\n诊断: ${data.root_cause}\n建议: 无匹配修复剧本，需人工排查`,
    task_id: data.task_id
  };
}

// 自愈成功 → 通知
if (data.success) {
  return {
    notify: true,
    channel: 'feishu',
    level: 'INFO',
    title: `✅ ${data.component} 自愈成功`,
    message: `${data.summary}\n耗时: ${data.duration_ms}ms`,
    task_id: data.task_id
  };
}

return { notify: false };
